import{_ as a,o as e,c as t,ag as i}from"./chunks/framework.DL0AyVxm.js";const u=JSON.parse('{"title":"Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"reference/permissions.md","filePath":"reference/permissions.md"}'),n={name:"reference/permissions.md"};function o(d,s,l,p,r,c){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h1><p>Worclaude configures pre-approved tool permissions in <code>.claude/settings.json</code>. These permissions let Claude use common development tools without prompting for confirmation on every invocation. Permissions are organized as an allow list.</p><h2 id="why-pre-approved-permissions" tabindex="-1">Why Pre-Approved Permissions <a class="header-anchor" href="#why-pre-approved-permissions" aria-label="Permalink to &quot;Why Pre-Approved Permissions&quot;">​</a></h2><p>Without pre-approved permissions, Claude Code asks for user confirmation on every shell command and file edit. This creates friction during normal development. Worclaude pre-approves safe, common operations so Claude can work fluidly while still requiring confirmation for unusual or destructive commands.</p><h2 id="permission-syntax" tabindex="-1">Permission Syntax <a class="header-anchor" href="#permission-syntax" aria-label="Permalink to &quot;Permission Syntax&quot;">​</a></h2><p>Permissions use the format <code>Tool(pattern)</code> where the pattern supports wildcards:</p><table tabindex="0"><thead><tr><th>Format</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>Bash(command:*)</code></td><td>Allow a shell command with any arguments</td><td><code>Bash(git status:*)</code></td></tr><tr><td><code>Edit(glob)</code></td><td>Allow editing files matching a glob pattern</td><td><code>Edit(src/**)</code></td></tr></tbody></table><p>The <code>*</code> wildcard matches any arguments. The <code>**</code> glob matches any path depth.</p><h2 id="universal-permissions-base" tabindex="-1">Universal Permissions (Base) <a class="header-anchor" href="#universal-permissions-base" aria-label="Permalink to &quot;Universal Permissions (Base)&quot;">​</a></h2><p>These permissions are installed for every project regardless of tech stack.</p><h3 id="read-only-exploration" tabindex="-1">Read-Only / Exploration <a class="header-anchor" href="#read-only-exploration" aria-label="Permalink to &quot;Read-Only / Exploration&quot;">​</a></h3><p>Commands that inspect without modifying:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>find, grep, cat, ls, head, tail, wc, which, tree, diff,</span></span>
<span class="line"><span>sort, uniq, awk, sed, cut, jq, xargs, ps, du, df, env, printenv</span></span></code></pre></div><h3 id="git" tabindex="-1">Git <a class="header-anchor" href="#git" aria-label="Permalink to &quot;Git&quot;">​</a></h3><p>Full git workflow including GitHub CLI:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git status, git log, git diff, git branch, git checkout,</span></span>
<span class="line"><span>git add, git commit, git push, git pull, git fetch, git merge,</span></span>
<span class="line"><span>git stash, git worktree, git rebase, git cherry-pick, git tag, gh</span></span></code></pre></div><h3 id="common-dev-tools" tabindex="-1">Common Dev Tools <a class="header-anchor" href="#common-dev-tools" aria-label="Permalink to &quot;Common Dev Tools&quot;">​</a></h3><p>General-purpose commands:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>echo, mkdir, touch, cp, mv, curl, wget, tar, zip, unzip, make</span></span></code></pre></div><h3 id="edit-permissions" tabindex="-1">Edit Permissions <a class="header-anchor" href="#edit-permissions" aria-label="Permalink to &quot;Edit Permissions&quot;">​</a></h3><p>File editing by path pattern:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Scope</th></tr></thead><tbody><tr><td><code>Edit(.claude/**)</code></td><td>All workflow configuration files</td></tr><tr><td><code>Edit(docs/**)</code></td><td>All documentation</td></tr><tr><td><code>Edit(src/**)</code></td><td>Source code</td></tr><tr><td><code>Edit(tests/**)</code>, <code>Edit(test/**)</code></td><td>Test files</td></tr><tr><td><code>Edit(README*)</code></td><td>README files</td></tr><tr><td><code>Edit(*.md)</code></td><td>Any Markdown file</td></tr><tr><td><code>Edit(package.json)</code></td><td>Node.js package manifest</td></tr><tr><td><code>Edit(pyproject.toml)</code></td><td>Python project config</td></tr><tr><td><code>Edit(.github/**)</code></td><td>GitHub Actions and configs</td></tr></tbody></table><h2 id="per-stack-permissions" tabindex="-1">Per-Stack Permissions <a class="header-anchor" href="#per-stack-permissions" aria-label="Permalink to &quot;Per-Stack Permissions&quot;">​</a></h2><p>Additional permissions are appended based on the selected tech stack. Each stack adds both Bash commands and Edit patterns for its ecosystem.</p><h3 id="python" tabindex="-1">Python <a class="header-anchor" href="#python" aria-label="Permalink to &quot;Python&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python, python3, pip, pip3, uv, uvx, pytest, ruff, mypy,</span></span>
<span class="line"><span>black, isort, flake8, poetry, pdm</span></span>
<span class="line"><span>Edit(*.py), Edit(pyproject.toml), Edit(requirements*.txt),</span></span>
<span class="line"><span>Edit(setup.py), Edit(setup.cfg)</span></span></code></pre></div><h3 id="node-js-typescript" tabindex="-1">Node.js / TypeScript <a class="header-anchor" href="#node-js-typescript" aria-label="Permalink to &quot;Node.js / TypeScript&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm, npx, node, tsc, tsx, jest, vitest, eslint, prettier,</span></span>
<span class="line"><span>pnpm, yarn, bun</span></span>
<span class="line"><span>Edit(*.ts), Edit(*.tsx), Edit(*.js), Edit(*.jsx), Edit(*.json),</span></span>
<span class="line"><span>Edit(*.css), Edit(*.scss), Edit(tsconfig*.json), Edit(.eslintrc*),</span></span>
<span class="line"><span>Edit(vite.config.*), Edit(next.config.*), Edit(webpack.config.*)</span></span></code></pre></div><h3 id="java" tabindex="-1">Java <a class="header-anchor" href="#java" aria-label="Permalink to &quot;Java&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>java, javac, javap, mvn, mvnw, gradle, gradlew, google-java-format</span></span>
<span class="line"><span>Edit(*.java), Edit(pom.xml), Edit(build.gradle*),</span></span>
<span class="line"><span>Edit(settings.gradle*), Edit(gradle.properties)</span></span></code></pre></div><h3 id="go" tabindex="-1">Go <a class="header-anchor" href="#go" aria-label="Permalink to &quot;Go&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>go, gofmt, golangci-lint</span></span>
<span class="line"><span>Edit(*.go), Edit(go.mod), Edit(go.sum)</span></span></code></pre></div><h3 id="rust" tabindex="-1">Rust <a class="header-anchor" href="#rust" aria-label="Permalink to &quot;Rust&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cargo, rustc, rustup, clippy</span></span>
<span class="line"><span>Edit(*.rs), Edit(Cargo.toml), Edit(Cargo.lock)</span></span></code></pre></div><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker, docker-compose, docker compose</span></span>
<span class="line"><span>Edit(Dockerfile*), Edit(docker-compose*), Edit(.dockerignore)</span></span></code></pre></div><p>Additional stack configs exist for C# / .NET, C / C++, PHP, Ruby, Kotlin, Swift, Dart / Flutter, Scala, Elixir, and Zig. Each follows the same pattern of adding relevant CLI tools and file edit permissions.</p><h2 id="adding-custom-permissions" tabindex="-1">Adding Custom Permissions <a class="header-anchor" href="#adding-custom-permissions" aria-label="Permalink to &quot;Adding Custom Permissions&quot;">​</a></h2><p>Edit <code>.claude/settings.json</code> directly to add permissions:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;// -- Custom --&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(terraform:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(kubectl:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Edit(*.tf)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Edit(k8s/**)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Comment strings (lines starting with <code>//</code>) are supported for organization. They are not valid JSON but Worclaude handles them for readability. The <code>worclaude status</code> command counts only non-comment permission rules.</p><h2 id="deny-list" tabindex="-1">Deny List <a class="header-anchor" href="#deny-list" aria-label="Permalink to &quot;Deny List&quot;">​</a></h2><p>The <code>permissions</code> object also supports a <code>deny</code> key for explicitly blocking commands. Worclaude does not install any deny rules by default, but they can be added manually:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [ </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;Bash(rm -rf:*)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/Worclaude/reference/hooks.html">Hooks</a> -- the other half of settings.json</li><li><a href="/Worclaude/reference/configuration.html">Configuration</a> -- full settings.json structure</li><li><a href="/Worclaude/reference/commands.html">CLI Commands</a> -- <code>worclaude status</code> reports permission rule counts</li></ul>`,47)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
